This is the autonomous self-edit path (no approval gate, per `CLAUDE.md`'s own description of the feature). Untested branches:

- `getActivePrompt`: no state row → fallback; state row with null `active_version` → fallback; version row missing/empty `body` → fallback; DB throws → fallback (catch swallows and logs).
- `isSelfEditEnabled`: no row → defaults `true`; explicit `false`; DB throws → **fails closed to `false`** (comment says so, but nothing verifies it).
- `applyEdit`: kill-switch off → rejected without writing; empty/whitespace body → rejected; body over `MAX_BODY_CHARS` → rejected; `maxRow` null → `nextVersion` becomes `1`; insert error → `ok:false`, state not flipped; upsert error → `ok:false` after insert already succeeded (inconsistent state — worth a comment/test even if not fixed).
- `revertTo`: non-integer/`NaN`/`<1` version → rejected before any DB call; target version doesn't exist → rejected; DB throws → caught.
- `executeSelfPromptTool`: unknown tool name → `isError:true`; non-string `new_body`/`reason` coerced to `""` (which then trips the empty-body rejection); `Number(args.to_version)` on a missing/non-numeric field → `NaN` → rejected by `revertTo`'s guard.

```ts
// src/lib/self-prompt.test.ts
import { describe, it, expect, vi, beforeEach } from "vitest";
import { applyEdit, revertTo, isSelfEditEnabled, getActivePrompt, executeSelfPromptTool, MAX_BODY_CHARS } from "./self-prompt";
import { createAdmin } from "@/lib/supabase/server";

vi.mock("@/lib/supabase/server", () => ({ createAdmin: vi.fn() }));

function mockAdmin(overrides: Record<string, any>) {
  const chain: any = {
    select: vi.fn(() => chain),
    eq: vi.fn(() => chain),
    order: vi.fn(() => chain),
    limit: vi.fn(() => chain),
    maybeSingle: vi.fn(),
    insert: vi.fn(),
    upsert: vi.fn(),
  };
  Object.assign(chain, overrides);
  (createAdmin as any).mockReturnValue({ from: vi.fn(() => chain) });
  return chain;
}

describe("isSelfEditEnabled", () => {
  it("defaults to true when no state row exists", async () => {
    mockAdmin({ maybeSingle: vi.fn().mockResolvedValue({ data: null }) });
    expect(await isSelfEditEnabled()).toBe(true);
  });

  it("fails closed (false) when the DB throws", async () => {
    mockAdmin({ maybeSingle: vi.fn().mockRejectedValue(new Error("down")) });
    expect(await isSelfEditEnabled()).toBe(false);
  });
});

describe("applyEdit", () => {
  it("rejects when the kill switch is off, without writing", async () => {
    const chain = mockAdmin({ maybeSingle: vi.fn().mockResolvedValue({ data: { self_edit_enabled: false } }) });
    const r = await applyEdit({ new_body: "new prompt", reason: "test" });
    expect(r.ok).toBe(false);
    expect(chain.insert).not.toHaveBeenCalled();
  });

  it("rejects empty/whitespace-only body", async () => {
    mockAdmin({ maybeSingle: vi.fn().mockResolvedValue({ data: { self_edit_enabled: true } }) });
    const r = await applyEdit({ new_body: "   ", reason: "test" });
    expect(r.ok).toBe(false);
    expect(r.message).toMatch(/empty/i);
  });

  it("rejects bodies over MAX_BODY_CHARS", async () => {
    mockAdmin({ maybeSingle: vi.fn().mockResolvedValue({ data: { self_edit_enabled: true } }) });
    const r = await applyEdit({ new_body: "a".repeat(MAX_BODY_CHARS + 1), reason: "test" });
    expect(r.ok).toBe(false);
    expect(r.message).toMatch(/over the/i);
  });

  it("increments version from null maxRow to 1", async () => {
    // needs two sequential maybeSingle() resolutions (enabled check, then max version)
  });
});

describe("revertTo", () => {
  it.each([0, -1, 1.5, NaN])("rejects invalid version %p before any DB call", async (v) => {
    const chain = mockAdmin({});
    const r = await revertTo(v as number);
    expect(r.ok).toBe(false);
    expect(chain.select).not.toHaveBeenCalled();
  });

  it("rejects when target version does not exist", async () => {
    mockAdmin({ maybeSingle: vi.fn().mockResolvedValue({ data: null }) });
    const r = await revertTo(99);
    expect(r.ok).toBe(false);
  });
});

describe("executeSelfPromptTool", () => {
  it("returns isError for unknown tool name", async () => {
    const r = await executeSelfPromptTool("delete_everything", {});
    expect(r.isError).toBe(true);
  });

  it("coerces non-string new_body/reason to empty string, then rejects as empty", async () => {
    mockAdmin({ maybeSingle: vi.fn().mockResolvedValue({ data: { self_edit_enabled: true } }) });
    const r = await executeSelfPromptTool("update_self_prompt", { new_body: 123, reason: null });
    expect(r.isError).toBe(true);
  });
});
```

