- `text === "NONE"` → `{ saved: false, reason: "not worth saving" }`
- `text.length < 10` (but not `"NONE"`) → same rejection
- Success path → `writeNote` called, returns `{ saved: true, noteId }`
- `writeNote` returns `null` → `{ saved: false, reason: "write failed" }`
- `quickResponse` throws → caught, `{ saved: false, reason: "error" }`
- Title derivation `text.split(".")[0].slice(0, 80)` when `text` has no period (whole string used, truncated at 80)

```ts
// src/lib/note-extraction.test.ts
import { describe, it, expect, vi } from "vitest";
import { extractAndSaveNote } from "./note-extraction";
import { quickResponse } from "./anthropic";
import { writeNote } from "./vault";

vi.mock("./anthropic", () => ({ quickResponse: vi.fn() }));
vi.mock("./vault", () => ({ writeNote: vi.fn() }));

describe("extractAndSaveNote", () => {
  it("returns saved:false when model says NONE", async () => {
    (quickResponse as any).mockResolvedValue({ text: "NONE" });
    const r = await extractAndSaveNote({ userMessage: "hi", assistantMessage: "hi", conversationId: "c1" });
    expect(r).toEqual({ saved: false, reason: "not worth saving" });
  });

  it("returns saved:false for too-short text even if not NONE", async () => {
    (quickResponse as any).mockResolvedValue({ text: "short" });
    const r = await extractAndSaveNote({ userMessage: "hi", assistantMessage: "hi", conversationId: "c1" });
    expect(r.saved).toBe(false);
  });

  it("saves and returns noteId on a real insight", async () => {
    (quickResponse as any).mockResolvedValue({ text: "Hudson decided to switch stacks entirely." });
    (writeNote as any).mockResolvedValue({ id: "note-1", path: "/x" });
    const r = await extractAndSaveNote({ userMessage: "u", assistantMessage: "a", conversationId: "c1" });
    expect(r).toEqual({ saved: true, noteId: "note-1" });
  });

  it("reports write failed when writeNote returns null", async () => {
    (quickResponse as any).mockResolvedValue({ text: "A note worth keeping around." });
    (writeNote as any).mockResolvedValue(null);
    const r = await extractAndSaveNote({ userMessage: "u", assistantMessage: "a", conversationId: "c1" });
    expect(r).toEqual({ saved: false, reason: "write failed" });
  });

  it("swallows thrown errors and reports reason:'error'", async () => {
    (quickResponse as any).mockRejectedValue(new Error("boom"));
    const r = await extractAndSaveNote({ userMessage: "u", assistantMessage: "a", conversationId: "c1" });
    expect(r).toEqual({ saved: false, reason: "error" });
  });
});
