`formatNotesForPrompt`/`formatPastMessagesForPrompt` are pure functions — cheap, high-value tests:

- Empty array → `""`
- Content truncated at 1500/600 chars with the right suffix
- Missing `title`/`folder` handled gracefully in the header
- `retrieveNotes`/`retrievePastMessages`: RPC error → logged + `[]` returned (not thrown)

```ts
// src/lib/rag.test.ts
import { describe, it, expect, vi } from "vitest";
import { formatNotesForPrompt, formatPastMessagesForPrompt, retrieveNotes } from "./rag";
import { createAdmin } from "./supabase/server";
import { embed } from "./embeddings";

vi.mock("./supabase/server");
vi.mock("./embeddings", () => ({ embed: vi.fn().mockResolvedValue([0.1]) }));

describe("formatNotesForPrompt", () => {
  it("returns empty string for no notes", () => {
    expect(formatNotesForPrompt([])).toBe("");
  });

  it("truncates content over 1500 chars and marks it", () => {
    const long = "x".repeat(2000);
    const out = formatNotesForPrompt([{ id: "1", path: "/p", title: null, content: long, folder: null, similarity: 0.9 }]);
    expect(out).toContain("[…truncated]");
    expect(out.length).toBeLessThan(long.length + 200);
  });
});

describe("retrieveNotes", () => {
  it("returns [] and logs when the RPC errors", async () => {
    (createAdmin as any).mockReturnValue({ rpc: vi.fn().mockResolvedValue({ data: null, error: new Error("rpc fail") }) });
    const notes = await retrieveNotes("query");
    expect(notes).toEqual([]);
  });
});
```

