- `sampleNotes`: error → `[]`; result length capped at `count` even when the pool is larger.
- `writeNote`: slug sanitization (`toLowerCase`, non-alnum → `-`, `.slice(0,50)`); default folder `"Silas-Authored"` when omitted; DB error → `null`.

```ts
// src/lib/vault.test.ts
import { describe, it, expect, vi } from "vitest";
import { sampleNotes, writeNote } from "./vault";
import { createAdmin } from "./supabase/server";
import { embed } from "./embeddings";

vi.mock("./supabase/server");
vi.mock("./embeddings", () => ({ embed: vi.fn().mockResolvedValue([0.1]) }));

describe("sampleNotes", () => {
  it("returns [] on query error", async () => {
    (createAdmin as any).mockReturnValue({
      from: () => ({ select: () => ({ not: () => ({ limit: vi.fn().mockResolvedValue({ data: null, error: new Error("x") }) }) }) }),
    });
    expect(await sampleNotes(20)).toEqual([]);
  });

  it("never returns more than `count` notes", async () => {
    const pool = Array.from({ length: 500 }, (_, i) => ({ id: String(i) }));
    (createAdmin as any).mockReturnValue({
      from: () => ({ select: () => ({ not: () => ({ limit: vi.fn().mockResolvedValue({ data: pool, error: null }) }) }) }),
    });
    const sample = await sampleNotes(20);
    expect(sample.length).toBe(20);
  });
});

describe("writeNote", () => {
  it("sanitizes the title into a URL-safe slug", async () => {
    let insertedPath = "";
    (createAdmin as any).mockReturnValue({
      from: () => ({
        insert: (row: any) => {
          insertedPath = row.path;
          return { select: () => ({ single: vi.fn().mockResolvedValue({ data: { id: "1", path: row.path }, error: null }) }) };
        },
      }),
    });
    await writeNote({ content: "hi", title: "Hello, World! 123" });
    expect(insertedPath).toMatch(/hello-world-123-\d+\.md$/);
  });

  it("returns null on insert error", async () => {
    (createAdmin as any).mockReturnValue({
      from: () => ({ insert: () => ({ select: () => ({ single: vi.fn().mockResolvedValue({ data: null, error: new Error("x") }) }) }) }),
    });
    expect(await writeNote({ content: "hi" })).toBeNull();
  });
});
```

