- `streamChat`: `tools` omitted from the request when `undefined` or `[]` (currently `...(params.tools && params.tools.length > 0 ? {...} : {})`); defaults for `model`/`maxTokens`.
- `quickResponse`: filters non-`text` content blocks; joins multiple text blocks; default model is `CHEAP_MODEL`, not `CHAT_MODEL`.

```ts
// src/lib/anthropic.test.ts
import { describe, it, expect, vi } from "vitest";
import { anthropic, streamChat, quickResponse, CHEAP_MODEL } from "./anthropic";

vi.mock("./anthropic", async (orig) => {
  const mod = await (orig as any)();
  return mod;
});

describe("streamChat", () => {
  it("omits `tools` from the request when the array is empty", async () => {
    const spy = vi.spyOn(anthropic.messages, "stream").mockReturnValue({} as any);
    await streamChat({ systemPrompt: "s", messages: [], tools: [] });
    expect(spy.mock.calls[0][0]).not.toHaveProperty("tools");
  });
});

describe("quickResponse", () => {
  it("defaults to CHEAP_MODEL, not CHAT_MODEL", async () => {
    vi.spyOn(anthropic.messages, "create").mockResolvedValue({ content: [{ type: "text", text: "hi" }], usage: {} } as any);
    await quickResponse({ systemPrompt: "s", userMessage: "u" });
    expect((anthropic.messages.create as any).mock.calls[0][0].model).toBe(CHEAP_MODEL);
  });

  it("joins only text blocks, ignoring others", async () => {
    vi.spyOn(anthropic.messages, "create").mockResolvedValue({
      content: [{ type: "text", text: "a" }, { type: "tool_use", id: "1", name: "x", input: {} }, { type: "text", text: "b" }],
      usage: {},
    } as any);
    const { text } = await quickResponse({ systemPrompt: "s", userMessage: "u" });
    expect(text).toBe("ab");
  });
});
```

