This is the core agentic loop and has the densest untested logic. Key scenarios, none currently covered:

1. Empty/whitespace `message` → `400`.
2. History filtering: `system` role dropped, blank-content rows dropped, **leading assistant rows shifted off** until the first `user` row (or history ends up empty).
3. Tool-use round-trip: model emits `tool_use` → `executeSelfPromptTool` called → `tool_result` appended → loop continues in the same turn.
4. `MAX_TOOL_ROUNDS` cap: if the model keeps returning `stop_reason: "tool_use"` past 6 rounds, the loop just ends (no explicit "give up" message is sent to the user) — worth a regression test so this doesn't start silently truncating replies unexpectedly.
5. Tool-only round (no text) → assistant message insert is **skipped** (avoids empty rows).
6. Conversation-creation DB error is thrown *before* the stream starts, so it's caught by the **outer** catch → `500`, not surfaced as an SSE `error` event. Worth asserting which path fires.
7. Mid-stream failure (e.g., embedding the assistant reply throws) → caught by the **inner** catch inside `ReadableStream.start`, emits an SSE `error` frame, and still calls `controller.close()` (stream doesn't hang open).
8. `extractAndSaveNote` runs fire-and-forget after `controller.close()` — a rejection there must not crash the response (only `console.error`).

```ts
// src/app/api/chat/route.test.ts
import { describe, it, expect, vi, beforeEach } from "vitest";
import { POST } from "./route";
import { createAdmin } from "@/lib/supabase/server";
import { streamChat } from "@/lib/anthropic";
import { embed } from "@/lib/embeddings";

vi.mock("@/lib/supabase/server");
vi.mock("@/lib/anthropic");
vi.mock("@/lib/embeddings", () => ({ embed: vi.fn().mockResolvedValue([0.1]) }));
vi.mock("@/lib/rag", () => ({ retrieveNotes: vi.fn().mockResolvedValue([]), retrievePastMessages: vi.fn().mockResolvedValue([]) }));
vi.mock("@/lib/prompts", () => ({ buildChatSystemPrompt: vi.fn().mockResolvedValue("system") }));
vi.mock("@/lib/note-extraction", () => ({ extractAndSaveNote: vi.fn().mockResolvedValue({ saved: false }) }));

function req(body: unknown) {
  return new Request("http://localhost/api/chat", { method: "POST", body: JSON.stringify(body) }) as any;
}

describe("POST /api/chat", () => {
  it("400s on empty message", async () => {
    const res = await POST(req({ conversationId: "c1", message: "   " }));
    expect(res.status).toBe(400);
  });

  it("drops leading assistant rows from history until the first user row", async () => {
    // Arrange messages table to return [assistant, assistant, user, assistant] (desc order reversed by route)
    // Assert the `messages` array passed into streamChat() starts with role:"user"
  });

  it("skips saving an assistant message when the turn produced no text (tool-only round)", async () => {
    // stub streamChat to yield stop_reason: 'tool_use' then a final round with no text deltas and stop_reason !== 'tool_use'
    // assert admin.from('messages').insert was never called with role: 'assistant'
  });

  it("stops after MAX_TOOL_ROUNDS even if the model keeps calling tools", async () => {
    // stub streamChat to always return stop_reason: 'tool_use'
    // assert streamChat was called exactly 6 times, and the response still completes (done event emitted)
  });

  it("emits an SSE error frame and closes the stream if mid-loop embedding fails", async () => {
    (embed as any).mockRejectedValueOnce(new Error("embed down"));
    const res = await POST(req({ conversationId: "c1", message: "hi" }));
    const text = await res.text();
    expect(text).toContain('"type":"error"');
  });
});
