- Already onboarded (`state.onboarded && state.onboarding_message`) → short-circuits, returns cached message, no Anthropic call.
- Not onboarded, empty vault → returns the "run pnpm migrate" message, `onboarded:false`.
- Not onboarded, has notes → calls Anthropic, upserts `user_state`, returns `justOnboarded:true`.
- Any thrown error → `500` JSON `{ onboarded:false, error }`.
- `POST` (dev reset) → flips `onboarded:false`, clears message, returns `{ reset:true }`.

```ts
// src/app/api/onboarding/route.test.ts
import { describe, it, expect, vi } from "vitest";
import { GET, POST } from "./route";
import { createAdmin } from "@/lib/supabase/server";
import { sampleNotes } from "@/lib/vault";
import { anthropic } from "@/lib/anthropic";

vi.mock("@/lib/supabase/server");
vi.mock("@/lib/vault");
vi.mock("@/lib/anthropic", () => ({ anthropic: { messages: { create: vi.fn() } }, CHAT_MODEL: "m" }));

describe("GET /api/onboarding", () => {
  it("returns cached message without calling Anthropic if already onboarded", async () => {
    (createAdmin as any).mockReturnValue({
      from: () => ({ select: () => ({ eq: () => ({ maybeSingle: vi.fn().mockResolvedValue({ data: { onboarded: true, onboarding_message: "hi" } }) }) }) }),
    });
    const res = await GET();
    const json = await res.json();
    expect(json).toEqual({ onboarded: true, message: "hi" });
    expect(anthropic.messages.create).not.toHaveBeenCalled();
  });

  it("tells the user to run migrate when the vault is empty", async () => {
    (createAdmin as any).mockReturnValue({ from: () => ({ select: () => ({ eq: () => ({ maybeSingle: vi.fn().mockResolvedValue({ data: null }) }) }) }) });
    (sampleNotes as any).mockResolvedValue([]);
    const res = await GET();
    const json = await res.json();
    expect(json.message).toMatch(/pnpm migrate/i);
  });

  it("returns 500 JSON on unexpected error", async () => {
    (createAdmin as any).mockImplementation(() => { throw new Error("db down"); });
    const res = await GET();
    expect(res.status).toBe(500);
  });
});
```

