- `code` present, exchange succeeds → redirect to `${origin}${next}`.
- `code` present, exchange fails → logs error, redirects to `/login?error=auth_failed`.
- `code` absent entirely → redirects to `/login?error=auth_failed` (no exchange attempted).
- Custom `next` param honored.

```ts
// src/app/api/auth/callback/route.test.ts
import { describe, it, expect, vi } from "vitest";
import { GET } from "./route";
import { createServer } from "@/lib/supabase/server";

vi.mock("@/lib/supabase/server");

describe("GET /api/auth/callback", () => {
  it("redirects to `next` on successful exchange", async () => {
    (createServer as any).mockResolvedValue({ auth: { exchangeCodeForSession: vi.fn().mockResolvedValue({ error: null }) } });
    const res = await GET(new Request("http://localhost/api/auth/callback?code=abc&next=/dashboard") as any);
    expect(res.headers.get("location")).toBe("http://localhost/dashboard");
  });

  it("redirects to /login?error=auth_failed when exchange fails", async () => {
    (createServer as any).mockResolvedValue({ auth: { exchangeCodeForSession: vi.fn().mockResolvedValue({ error: new Error("bad code") }) } });
    const res = await GET(new Request("http://localhost/api/auth/callback?code=bad") as any);
    expect(res.headers.get("location")).toBe("http://localhost/login?error=auth_failed");
  });

  it("redirects to /login?error=auth_failed when no code is present", async () => {
    const res = await GET(new Request("http://localhost/api/auth/callback") as any);
    expect(res.headers.get("location")).toBe("http://localhost/login?error=auth_failed");
  });
});
```

