vi.mock("./vault", () => ({ writeNote: vi.fn() }));

describe("extractAndSaveNote", () => {
  it("returns saved:false when model says NONE", async () => {
    (quickResponse as any).mockResolvedValue({ text: "NONE" });
    const r = await extractAndSaveNote({ userMessage: "hi", assistantMessage: "hi", conversationId: "c1" });
    expect(r).toEqual({ saved: false, reason: "not worth saving" });
  });

  it("returns saved:false for too-short text even if not NONE", async () => {
    (quickResponse as any).mockResolvedValue({ text: "short" });
    const r = await extractAndSaveNote({ userMessage: "hi", assistantMessage: "hi", conversationId: "c1" });
